from flask import Flask, request, jsonify, session
from itsdangerous import URLSafeTimedSerializer, BadSignature
import pyotp

app = Flask(__name__)
app.secret_key = 'your_secret_key'
serializer = URLSafeTimedSerializer(app.secret_key)

# Dummy user database
users = {
    'user1': {'password': 'password1', 'mfa_enabled': True},
    'user2': {'password': 'password2', 'mfa_enabled': False}
}

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']

    if username in users and users[username]['password'] == password:
        session['username'] = username
        if users[username]['mfa_enabled']:
            return jsonify({'message': 'MFA required. Please enter OTP.'}), 200
        else:
            return jsonify({'message': 'Login successful'}), 200
    else:
        return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/api/direct-login', methods=['POST'])
def direct_login():
    username = request.form['username']
    password = request.form['password']

    if username in users and users[username]['password'] == password:
        session['username'] = username
        return jsonify({'message': 'Login successful'}), 200
    else:
        return jsonify({'message': 'Invalid credentials'}), 401

@app.route('/verify-otp', methods=['POST'])
def verify_otp():
    otp = request.form['otp']
    username = session.get('username')

    if username and users[username]['mfa_enabled']:
        totp = pyotp.TOTP(users[username]['secret_key'])
        if totp.verify(otp):
            return jsonify({'message': 'Login successful'}), 200
        else:
            return jsonify({'message': 'Invalid OTP'}), 401
    else:
        return jsonify({'message': 'MFA not required or user not logged in'}), 400

